        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));

        // Union-Find data structure
        UnionFind uf = new UnionFind(n);

        // We'll use binary search on the time to find the minimum t
        long left = 0, right = 0;
        for (long[] edge : edges) {
            right = Math.max(right, edge[2]);
        }

        // Binary search
        long answer = right;
        while (left <= right) {
            long mid = (left + right) / 2;
