public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        // Sort edges by their removal time
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));

        // Union-Find (Disjoint Set Union) data structure
        long[] parent = new long[(int) n];
        long[] rank = new long[(int) n];

        // Initialize DSU
        for (long i = 0; i < n; i++) {
            parent[i] = i;
            rank[i] = 1;
        }

        // Function to find the root of a node
        private long find(long x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        // Function to union two nodes
        private void union(long x, long y) {
            long rootX = find(x);
            long rootY = find(y);
            if (rootX != rootY) {
                if (rank[rootX] > rank[rootY]) {
                    parent[rootY] = rootX;
                } else if (rank[rootX] < rank[rootY]) {
                    parent[rootX] = rootY;
                } else {
                    parent[rootY] = rootX;
                    rank[rootX]++;
                }
            }
        }

        // Count the number of connected components
        private long countComponents() {
            long count = 0;
            for (long i = 0; i < n; i++) {
                if (find(i) == i) {
                    count++;
                }
            }
            return count;
        }

        // Process edges in order of removal time
        long result = 0;
        for (long[] edge : edges) {
            long u = (long) edge[0];
            long v = (long) edge[1];
            long time = edge[2];

            // Remove the edge by unioning the nodes (reverse of adding)
            union(u, v);

            // Check if the number of connected components is at least k
            if (countComponents() >= k) {
                result = time;
                break;
            }
        }

        return result;
    }
